    return len;
}

vector<long long> solve(vector<string> words) {
    int n = words.size();
    if (n == 1) {
        return {0};
    }
    vector<int> prefixes(n - 1, 0);
    for (int j = 0; j < n - 1; j++) {
        prefixes[j] = commonPrefixLength(words[j], words[j + 1]);
    }
    vector<int> left_max(n - 1, 0);
    left_max[0] = prefixes[0];
    for (int i = 1; i < n - 1; i++) {
        left_max[i] = max(left_max[i - 1], prefixes[i]);
    }
    vector<int> right_max(n - 1, 0);
    right_max[n - 2] = prefixes[n - 2];
    for (int i = n - 3; i >= 0; i--) {
        right_max[i] = max(right_max[i + 1], prefixes[i]);
    }
    vector<long long> answer(n, 0);
    for (int i = 0; i < n; i++) {
        if (n == 2) {
